sp_widget.client_script:
function($scope) {
    var c = this;
    // Page title and description driven by options set on the widget instance
    c.pageTitle = c.options.page_title || 'IDP Page';
    c.pageDesc = c.options.page_description || 'This page is under construction.';
    c.catalogData = c.data.catalogData || {};
    c.hasItems = Object.keys(c.catalogData).length > 0;
}

sp_widget.css:
.idp-placeholder { padding: 2rem; }
.idp-placeholder-title { font-size: 1.75rem; font-weight: 300; color: var(--cds-text-01, #161616); margin-bottom: 0.5rem; }
.idp-placeholder-desc { font-size: 0.875rem; color: var(--cds-text-02, #525252); margin-bottom: 2rem; }
.idp-catalog-group { margin-bottom: 2rem; }
.idp-catalog-group-title {
  font-size: 1rem; font-weight: 600; color: var(--cds-text-01, #161616);
  padding-bottom: 0.5rem; border-bottom: 1px solid var(--cds-ui-03, #e0e0e0); margin-bottom: 1rem;
}
.idp-catalog-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(240px, 1fr)); gap: 1px; background-color: var(--cds-ui-03, #e0e0e0); }
.idp-catalog-card {
  background-color: var(--cds-ui-02, #fff); padding: 1rem;
  cursor: pointer; transition: background-color 70ms; min-height: 80px;
}
.idp-catalog-card:hover { background-color: var(--cds-hover-ui, #e5e5e5); }
.idp-catalog-card-name { font-size: 0.875rem; font-weight: 600; margin-bottom: 0.25rem; color: var(--cds-text-01, #161616); }
.idp-catalog-card-desc { font-size: 0.75rem; color: var(--cds-text-02, #525252); }
.idp-catalog-card-meta { margin-top: 0.5rem; display: flex; gap: 0.25rem; flex-wrap: wrap; }
.idp-tag { display: inline-flex; align-items: center; padding: 0 0.5rem; height: 1.25rem; border-radius: 0.625rem; font-size: 0.6875rem; background-color: var(--cds-ui-03, #e0e0e0); color: var(--cds-text-02, #525252); }
.idp-tag-alpha { background-color: #fdd13a; color: #3e2400; }
.idp-tag-beta { background-color: #d0e2ff; color: #0043ce; }
.idp-tag-ga { background-color: #defbe6; color: #0e6027; }
.idp-empty { padding: 3rem 2rem; text-align: center; color: var(--cds-text-02, #525252); background-color: var(--cds-ui-01, #f4f4f4); border: 1px dashed var(--cds-ui-04, #8d8d8d); }

sp_widget.option_schema:
[
  {"name":"page_title","label":"Page Title","hint":"Displayed as the page heading","default_value":"Service Catalog","fieldType":"String"},
  {"name":"page_description","label":"Page Description","hint":"Subtitle shown below the heading","default_value":"Browse and request platform services.","fieldType":"String"},
  {"name":"filter_taxonomy","label":"Filter by Taxonomy Name","hint":"Leave blank to show all accessible items. Enter taxonomy name to filter (e.g. CI/CD Services).","default_value":"","fieldType":"String"}
]

sp_widget.script:
(function() {
    var userId = gs.getUserID();
    var filterTaxonomy = options.filter_taxonomy || '';

    var catalogEngine = new x_146833_idpkiro.IDPCatalogEngine();
    var grouped = catalogEngine.filterCatalogForPortal(userId);

    // Apply taxonomy filter if set
    if (filterTaxonomy) {
        var filtered = {};
        for (var key in grouped) {
            if (key.toLowerCase().indexOf(filterTaxonomy.toLowerCase()) !== -1) {
                filtered[key] = grouped[key];
            }
        }
        data.catalogData = filtered;
    } else {
        data.catalogData = grouped;
    }
})();
